<script>
  (function () {
    var island = document.querySelector(".ewc-nav-island");
    var toggle = island ? island.querySelector(".ewc-nav-toggle") : null;
    var panel = island ? island.querySelector(".ewc-nav-panel") : null;
    var closeButton = island ? island.querySelector(".ewc-nav-close") : null;
    var overlay = island ? island.querySelector(".ewc-nav-overlay") : null;

    if (!island || !toggle || !panel || !closeButton || !overlay) {
      return;
    }

    function closeNav() {
      island.classList.remove("ewc-nav-open");
      toggle.setAttribute("aria-expanded", "false");
    }

    function toggleNav() {
      var isOpen = island.classList.toggle("ewc-nav-open");
      toggle.setAttribute("aria-expanded", isOpen ? "true" : "false");
    }

    toggle.addEventListener("click", function (event) {
      event.stopPropagation();
      toggleNav();
    });

    closeButton.addEventListener("click", function (event) {
      event.stopPropagation();
      closeNav();
    });

    overlay.addEventListener("click", closeNav);

    panel.querySelectorAll("a").forEach(function (link) {
      link.addEventListener("click", closeNav);
    });

    document.addEventListener("click", function (event) {
      if (!island.contains(event.target)) {
        closeNav();
      }
    });

    window.addEventListener("resize", function () {
      if (window.innerWidth > 920) {
        closeNav();
      }
    });

    document.addEventListener("keydown", function (event) {
      if (event.key === "Escape") {
        closeNav();
      }
    });
  })();

  (function () {
    var images = Array.from(document.querySelectorAll(".ewc-inline-proof-card img"));

    if (!images.length) {
      return;
    }

    var lightbox = document.createElement("div");
    lightbox.className = "ewc-lightbox";
    lightbox.innerHTML = [
      '<div class="ewc-lightbox-dialog" role="dialog" aria-modal="true" aria-label="Expanded chart image">',
      '<button class="ewc-lightbox-close" type="button" aria-label="Close enlarged chart">&times;</button>',
      '<div class="ewc-lightbox-image-wrap"><img class="ewc-lightbox-image" alt="" /></div>',
      '<p class="ewc-lightbox-caption"></p>',
      "</div>"
    ].join("");
    document.body.appendChild(lightbox);

    var dialog = lightbox.querySelector(".ewc-lightbox-dialog");
    var lightboxImage = lightbox.querySelector(".ewc-lightbox-image");
    var caption = lightbox.querySelector(".ewc-lightbox-caption");
    var closeButton = lightbox.querySelector(".ewc-lightbox-close");

    function closeLightbox() {
      lightbox.classList.remove("is-open");
      document.body.style.overflow = "";
    }

    function openLightbox(image) {
      lightboxImage.src = image.currentSrc || image.src;
      lightboxImage.alt = image.alt || "";
      caption.textContent = image.alt || "";
      lightbox.classList.add("is-open");
      document.body.style.overflow = "hidden";
    }

    images.forEach(function (image) {
      image.setAttribute("tabindex", "0");
      image.setAttribute("role", "button");
      image.setAttribute("aria-label", (image.alt || "Chart image") + ". Open enlarged view");

      image.addEventListener("click", function () {
        openLightbox(image);
      });

      image.addEventListener("keydown", function (event) {
        if (event.key === "Enter" || event.key === " ") {
          event.preventDefault();
          openLightbox(image);
        }
      });
    });

    closeButton.addEventListener("click", closeLightbox);

    lightbox.addEventListener("click", function (event) {
      if (!dialog.contains(event.target)) {
        closeLightbox();
      }
    });

    document.addEventListener("keydown", function (event) {
      if (event.key === "Escape" && lightbox.classList.contains("is-open")) {
        closeLightbox();
      }
    });
  })();
